'use client';

import type { LucideIcon } from 'lucide-react';
import { PageHeader, EmptyState } from '@/components/shared';
import { findNavigationItemByPath } from '@/constants/navigation';
import { usePathname } from 'next/navigation';

interface ModulePlaceholderProps {
  title?: string;
  description?: string;
  icon?: LucideIcon;
}

/**
 * Generic placeholder for routes whose business modules are not implemented yet.
 */
export function ModulePlaceholder({ title, description, icon }: ModulePlaceholderProps) {
  const pathname = usePathname();
  const navItem = findNavigationItemByPath(pathname);
  const resolvedTitle = title ?? navItem?.label ?? 'Module';
  const ResolvedIcon = icon ?? navItem?.icon;

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title={resolvedTitle}
        description={
          description ??
          'This module will be implemented in a future phase. Navigation and permissions are already wired.'
        }
      />
      <EmptyState
        icon={ResolvedIcon}
        title={`${resolvedTitle} coming soon`}
        description="Use the sidebar to explore other areas you have access to."
      />
    </div>
  );
}
